"""
sleep.py — Asynchronous Memory Consolidation & Checkpointing

Runs as a background thread during live agent execution.
All macro-adjustments to the embedding space happen here — never on the
hot retrieval path.

Five sequential operations per consolidation cycle:
  1. Temporal Decay       — phase-shift stale chunks toward neutral
  2. Synaptic Alignment   — phase-align heavily co-activated chunk pairs
  3. Group Recomputation  — recompute group centroids after membership changes
  4. Emergent Families    — discover natural phase bands via histogram clustering
  5. Checkpoint Flush     — save_state() to sidecar disk

The SleepManager can be triggered manually (fast_sleep) or run on a
configurable background interval.
"""

from __future__ import annotations

import logging
import math
import threading
import time
from dataclasses import dataclass, field
from pathlib import Path
from typing import Dict, List, Optional, Tuple

import numpy as np

from .frequency import FrequencyFamily
from .memory_map import ResonanceRegistry

log = logging.getLogger("prismresonance.sleep")


# ─────────────────────────────────────────────────────────────────────────────
# Configuration
# ─────────────────────────────────────────────────────────────────────────────

@dataclass
class SleepConfig:
    """Tunable parameters for the consolidation cycle."""

    # Temporal decay
    decay_lambda: float = 1.0 / 3600.0   # e-fold per 1 hour of staleness
    decay_threshold: float = 3600.0       # seconds idle before decay starts
    phase_drift_rate: float = 0.05        # how fast φ drifts toward NEUTRAL per cycle

    # Synaptic alignment
    co_activation_threshold: int = 5      # W_xy > this triggers phase alignment
    alpha: float = 0.15                   # blend weight for phase update

    # Group membership
    join_threshold: float = 0.3           # resonance score to admit a chunk to a group
    evict_threshold: float = 0.1          # resonance score below which chunk is evicted

    # Group co-activation merge
    group_merge_threshold: int = 20       # group-level W > this triggers phase merge

    # Emergent frequency families
    emergent_families_enabled: bool = True
    emergent_min_chunks: int = 10         # minimum corpus size to attempt clustering
    emergent_n_bins: int = 12             # histogram bins across [0, π]
    emergent_peak_min_fraction: float = 0.05  # bin must hold ≥ this fraction to be a peak

    # Checkpoint
    state_path: str = "resonance_state.db"

    # Interval
    interval_seconds: float = 300.0       # background sleep cycle interval


# ─────────────────────────────────────────────────────────────────────────────
# Emergent family result
# ─────────────────────────────────────────────────────────────────────────────

@dataclass
class EmergentBand:
    """A discovered phase band from histogram clustering."""
    center_phi: float          # center phase angle of the band (radians)
    member_count: int          # how many chunks fall in this band
    nearest_family: str        # closest named FrequencyFamily


# ─────────────────────────────────────────────────────────────────────────────
# Sleep Manager
# ─────────────────────────────────────────────────────────────────────────────

class SleepManager:
    """
    Asynchronous memory consolidation manager.

    Usage — background mode (runs on a timer thread):
        manager = SleepManager(registry, config)
        manager.start()
        # ... agent runs ...
        manager.stop()

    Usage — manual / fast sleep:
        manager = SleepManager(registry, config)
        manager.fast_sleep()   # one blocking consolidation pass
    """

    def __init__(
        self,
        registry: ResonanceRegistry,
        config: Optional[SleepConfig] = None,
    ) -> None:
        self._reg    = registry
        self._cfg    = config or SleepConfig()
        self._thread: Optional[threading.Thread] = None
        self._stop   = threading.Event()
        self._lock   = threading.Lock()   # guards registry during consolidation

        # Most recent emergent bands discovered — readable by callers
        self._last_emergent_bands: List[EmergentBand] = []

    # ── Public API ────────────────────────────────────────────────────────

    def start(self) -> None:
        """Start the background consolidation thread."""
        if self._thread and self._thread.is_alive():
            return
        self._stop.clear()
        self._thread = threading.Thread(
            target=self._loop,
            name="prismresonance-sleep",
            daemon=True,
        )
        self._thread.start()
        log.info("SleepManager started (interval=%.0fs)", self._cfg.interval_seconds)

    def stop(self, flush: bool = True) -> None:
        """Stop the background thread and optionally flush state."""
        self._stop.set()
        if self._thread:
            self._thread.join(timeout=10)
        if flush:
            self.fast_sleep()
        log.info("SleepManager stopped")

    def fast_sleep(self) -> None:
        """
        Run one full consolidation cycle synchronously (blocking).
        Safe to call from the main thread — uses the same internal lock.
        """
        with self._lock:
            log.debug("fast_sleep: starting consolidation cycle")
            stats = {}
            stats["decayed"]   = self._run_temporal_decay()
            stats["aligned"]   = self._run_synaptic_alignment()
            stats["groups"]    = self._run_group_recomputation()
            stats["merged"]    = self._run_group_merge()
            stats["bands"]     = self._run_emergent_families()
            self._checkpoint()
            log.info(
                "fast_sleep complete: decayed=%d aligned=%d groups=%d merged=%d bands=%d",
                stats["decayed"], stats["aligned"], stats["groups"],
                stats["merged"], stats["bands"],
            )

    @property
    def emergent_bands(self) -> List[EmergentBand]:
        """Return the most recently discovered emergent frequency bands."""
        return list(self._last_emergent_bands)

    # ── Background loop ───────────────────────────────────────────────────

    def _loop(self) -> None:
        while not self._stop.wait(timeout=self._cfg.interval_seconds):
            try:
                self.fast_sleep()
            except Exception:
                log.exception("SleepManager: unhandled error in consolidation cycle")

    # ── Consolidation passes ──────────────────────────────────────────────

    def _run_temporal_decay(self) -> int:
        """
        Decay stale chunks: shift their phase toward NEUTRAL.
        Returns count of chunks decayed.
        """
        now     = time.time()
        neutral = FrequencyFamily.NEUTRAL.value
        count   = 0

        for cid, meta in self._reg._chunks.items():
            staleness = now - meta.last_access
            if staleness < self._cfg.decay_threshold:
                continue

            rate = self._cfg.phase_drift_rate * (
                1.0 + min(1.0, abs(meta.phase_velocity) * 100)
            )
            old_phi = meta.phi
            new_phi = old_phi + rate * (neutral - old_phi)
            meta.update_phase(new_phi)
            count += 1

        return count

    def _run_synaptic_alignment(self) -> int:
        """
        Phase-align heavily co-activated chunk pairs.
        Returns count of pairs aligned.
        """
        alpha   = self._cfg.alpha
        thresh  = self._cfg.co_activation_threshold
        count   = 0

        for (id_a, id_b), weight in list(self._reg._chunk_coact.items()):
            if weight < thresh:
                continue
            meta_a = self._reg._chunks.get(id_a)
            meta_b = self._reg._chunks.get(id_b)
            if meta_a is None or meta_b is None:
                continue

            phi_a_new = (1 - alpha) * meta_a.phi + alpha * meta_b.phi
            phi_b_new = (1 - alpha) * meta_b.phi + alpha * meta_a.phi

            meta_a.update_phase(phi_a_new)
            meta_b.update_phase(phi_b_new)

            # Phase changed — centroid needs refresh even if group unchanged
            if meta_a.group_id:
                self._reg._dirty_groups.add(meta_a.group_id)
            if meta_b.group_id:
                self._reg._dirty_groups.add(meta_b.group_id)

            self._maybe_reassign_group(id_a, phi_a_new)
            self._maybe_reassign_group(id_b, phi_b_new)

            self._reg._chunk_coact[(id_a, id_b)] = max(0, weight - thresh)
            count += 1

        return count

    def _maybe_reassign_group(self, chunk_id: str, new_phi: float) -> None:
        """If a chunk's phase has shifted significantly, reassign its group."""
        meta = self._reg._chunks.get(chunk_id)
        if meta is None:
            return
        nearest = FrequencyFamily.nearest(new_phi).name
        if nearest != meta.group_id:
            self._reg.add_chunk_to_group(chunk_id, nearest)

    def _run_group_recomputation(self) -> int:
        """
        Recompute group centroids — ONLY for groups marked dirty since the
        last cycle.  Unchanged groups are skipped entirely.
        Returns count of groups updated.
        """
        return self._reg.recompute_dirty_groups()

    def _run_group_merge(self) -> int:
        """
        Merge groups with high cross-group co-activation by aligning phases.
        Returns count of group pairs merged.
        """
        alpha   = self._cfg.alpha
        thresh  = self._cfg.group_merge_threshold
        count   = 0

        for gid_a, grp_a in list(self._reg._groups.items()):
            for gid_b, weight in list(grp_a.co_activations.items()):
                if weight < thresh:
                    continue
                grp_b = self._reg._groups.get(gid_b)
                if grp_b is None:
                    continue

                phi_a_new = (1 - alpha) * grp_a.phi + alpha * grp_b.phi
                phi_b_new = (1 - alpha) * grp_b.phi + alpha * grp_a.phi
                grp_a.phi = phi_a_new
                grp_b.phi = phi_b_new

                grp_a.co_activations[gid_b] = max(0, weight - thresh)
                count += 1

        return count

    def _run_emergent_families(self) -> int:
        """
        Discover emergent frequency bands by histogramming chunk phase angles.

        Chunks concentrate naturally around learned operational contexts.
        Peaks in the phase histogram reveal bands that the agent has actually
        used — regardless of which named FrequencyFamily was assigned at ingest.

        Returns the number of emergent bands found.
        """
        if not self._cfg.emergent_families_enabled:
            return 0

        phis = [m.phi for m in self._reg._chunks.values()]
        if len(phis) < self._cfg.emergent_min_chunks:
            return 0

        # Histogram over [0, π] — the full phase range used by FrequencyFamily
        phi_arr = np.array(phis, dtype=np.float32)
        # Clip to [0, π] to match FrequencyFamily range
        phi_arr = np.clip(phi_arr, 0.0, math.pi)

        counts, bin_edges = np.histogram(
            phi_arr,
            bins=self._cfg.emergent_n_bins,
            range=(0.0, math.pi),
        )

        total = len(phis)
        min_count = max(1, int(total * self._cfg.emergent_peak_min_fraction))

        bands: List[EmergentBand] = []
        for i, count in enumerate(counts):
            if count < min_count:
                continue
            # Check it's a local peak (higher than both neighbours)
            left  = counts[i - 1] if i > 0 else 0
            right = counts[i + 1] if i < len(counts) - 1 else 0
            if count < left or count < right:
                continue

            center = float((bin_edges[i] + bin_edges[i + 1]) / 2)
            nearest = FrequencyFamily.nearest(center)
            bands.append(EmergentBand(
                center_phi=center,
                member_count=int(count),
                nearest_family=nearest.name,
            ))

        self._last_emergent_bands = bands

        if bands:
            band_strs = [
                f"{b.nearest_family}(φ={b.center_phi:.2f}, n={b.member_count})"
                for b in bands
            ]
            log.info("Emergent frequency bands: %s", ", ".join(band_strs))

        return len(bands)

    def _checkpoint(self) -> None:
        """Flush registry to sidecar disk."""
        path = Path(self._cfg.state_path)
        self._reg.save_state(path)
        log.debug("Checkpoint written to %s", path)
